package main

import (
	"strings"
	"text/template"
)

func joinArgs(args []tplArg, sep string) string {
	var parts []string
	for _, a := range args {
		parts = append(parts, a.ParamName+" "+a.GoType)
	}
	return strings.Join(parts, sep)
}

var templateFuncs = template.FuncMap{
	"lower":    strings.ToLower,
	"joinArgs": joinArgs,
}

func mustTmpl(name, text string) *template.Template {
	return template.Must(template.New(name).Funcs(templateFuncs).Parse(text))
}

// fileTemplates render one generated file in order.
var fileTemplates = []*template.Template{
	headerTmpl,
	fdCountsTmpl,
	enumTmpl,
	requestStructsTmpl,
	eventStructsTmpl,
	wrapperTmpl,
	bindTmpl,
}

// headerTmpl renders the generated file header.
var headerTmpl = mustTmpl("header", `// Code generated by wayland-scanner. DO NOT EDIT.

package {{.Package}}
{{if .Imports}}
import ({{.Imports}})
{{end}}
const Interface{{.TypeName}} = "{{.IfName}}"
const Version{{.TypeName}} = {{.Version}}
{{if .Requests}}
const (
{{range .Requests}}	{{.OpName}} uint16 = {{.Opcode}}
{{end}})
{{end}}
{{if .Events}}
const (
{{range .Events}}	{{.OpName}} uint16 = {{.Opcode}}
{{end}})
{{end}}
`)

// fdCountsTmpl renders the per-opcode fd count table for events carrying fds.
var fdCountsTmpl = mustTmpl("fdCounts", `{{if .HasFDEvent}}
var {{lower .TypeName}}EventFDCounts = map[uint16]int{
{{range $opcode, $count := .EventFDCounts}}	{{$opcode}}: {{$count}},
{{end}}}
{{end}}
`)

// enumTmpl renders enum types and value constants.
var enumTmpl = mustTmpl("enums", `{{range $e := .Enums}}
type {{$e.Type}} uint32

const (
{{range $e.Entries}}	{{.Const}} {{$e.Type}} = {{.Val}}
{{end}})
{{end}}
`)

// requestStructsTmpl renders request structs implementing wire.Marshaler.
var requestStructsTmpl = mustTmpl("requests", `{{range .Requests}}
type {{.StructName}} struct {
{{range .Args}}	{{.GoName}} {{.GoType}}
{{end}}}

func (r *{{.StructName}}) Opcode() uint16 { return {{.OpName}} }

func (r *{{.StructName}}) Marshal(w *wire.Writer) error {
{{range .Args}}	if err := w.{{.WriteFn}}(r.{{.GoName}}); err != nil {
		return err
	}
{{end}}	return nil
}

func (r *{{.StructName}}) Since() int { return {{.Since}} }
{{end}}
`)

// eventStructsTmpl renders event structs implementing wire.Unmarshaler and
// their named callback function types.
var eventStructsTmpl = mustTmpl("events", `{{range .Events}}
type {{.StructName}} struct {
{{range .Args}}	{{.GoName}} {{.GoType}}
{{end}}}

func (e *{{.StructName}}) Opcode() uint16 { return {{.OpName}} }

func (e *{{.StructName}}) Unmarshal(r *wire.Reader) error {
{{range .Args}}	{{.ParamName}}, err := {{.WireRead}}
	if err != nil {
		return err
	}
	e.{{.GoName}} = {{.ParamName}}
{{end}}	return nil
}

func (e *{{.StructName}}) Since() int { return {{.Since}} }
{{end}}
{{range .Events}}
type {{.FuncName}} func(ev {{.StructName}})
{{end}}
`)

// wrapperTmpl renders the high-level typed wrapper: constructor, event
// registration methods and request methods.
var wrapperTmpl = mustTmpl("wrapper", `type {{.TypeName}} struct {
	proxy *{{.WaylandPkg}}Proxy
}

func New{{.TypeName}}(p *{{.WaylandPkg}}Proxy) *{{.TypeName}} {
{{if .HasFDEvent}}	p.SetEventFDCounts({{lower .TypeName}}EventFDCounts)
{{end}}	return &{{.TypeName}}{proxy: p}
}

func (o *{{.TypeName}}) Proxy() *{{.WaylandPkg}}Proxy {
	return o.proxy
}
{{range .Events}}
func (o *{{$.TypeName}}) On{{.Name}}(fn {{.FuncName}}) {
	o.proxy.RegisterEvent({{.OpName}}, func(r *wire.Reader) {
		var ev {{.StructName}}
		if err := ev.Unmarshal(r); err != nil {
			o.proxy.Conn().Logger().Warn("event unmarshal error", "event", "{{.Name}}", "error", err)
			return
		}
		fn(ev)
	})
}
{{end}}
{{range .Requests}}
{{if or .HasNewID .HasCrossNewID}}
func (o *{{$.TypeName}}) {{.Name}}({{.MethodArgs}}) ({{if .HasNewID}}*{{.NewIDType}}{{else}}*{{$.WaylandPkg}}Proxy{{end}}, error) {
{{if gt .Since 1}}	if v := o.proxy.Version(); v > 0 && v < uint32({{.Since}}) {
		return nil, {{$.WaylandPkg}}ErrVersionMismatch
	}
{{end}}	conn := o.proxy.Conn()
	p := {{$.WaylandPkg}}NewProxy(conn)
	p.SetVersion(o.proxy.Version())
{{if .HasNewID}}	wrapped := New{{.NewIDType}}(p)
{{end}}	conn.RegisterProxy(p)
	err := conn.SendRequest(o.proxy.ID(), {{.OpName}}, &{{.StructName}}{
{{range .Args}}{{if .IsNewID}}		{{.GoName}}: wire.NewID(p.ID()),
{{else}}		{{.GoName}}: {{.ParamName}},
{{end}}{{end}}	})
	if err != nil {
		conn.UnregisterProxy(p.ID())
		return nil, err
	}
	return {{if .HasNewID}}wrapped{{else}}p{{end}}, nil
}
{{else}}
func (o *{{$.TypeName}}) {{.Name}}({{joinArgs .Args ", "}}) error {
	return o.proxy.SendRequest({{.OpName}}, &{{.StructName}}{
{{range .Args}}		{{.GoName}}: {{.ParamName}},
{{end}}	})
}
{{end}}
{{end}}
`)

// bindTmpl renders the BindXxx registry factory.
var bindTmpl = mustTmpl("bind", `func Bind{{.TypeName}}(b {{.WaylandPkg}}Binder, name uint32, version uint32) (*{{.TypeName}}, error) {
	if version < 1 || version > Version{{.TypeName}} {
		return nil, {{.WaylandPkg}}ErrVersionMismatch
	}
	p, err := b.Bind(name, Interface{{.TypeName}}, version)
	if err != nil {
		return nil, err
	}
	x := New{{.TypeName}}(p)
	x.proxy.SetVersion(version)
	return x, nil
}
`)
